// Parse and normalize job data from various sources
// Adjust field mappings based on your job board's API response

const items = $input.all();
const jobs = [];

for (const item of items) {
  const data = item.json;

  // Skip non-job entries (e.g., RemoteOK's first item is metadata)
  if (!data.position && !data.title && !data.job_title) continue;

  const job = {
    title: data.position || data.title || data.job_title || 'Unknown Title',
    company: data.company || data.company_name || data.organization || 'Unknown Company',
    location: data.location || data.candidate_required_location || data.job_location || 'Remote',
    url: data.url || data.apply_url || data.link || '',
    description: (data.description || data.summary || data.job_description || '').substring(0, 500),
    tags: data.tags || data.categories || data.keywords || [],
    salary: data.salary || data.salary_range || data.compensation || 'Not specified',
    postedDate: data.date || data.publication_date || data.created_at || new Date().toISOString(),
    source: 'RemoteOK',
    scrapedAt: new Date().toISOString(),
    // Create a unique ID from URL or title+company combo
    uniqueId: (data.url || data.apply_url || data.link || `${data.position}-${data.company}`).toLowerCase().trim()
  };

  // Only add if we have minimum required fields
  if (job.title !== 'Unknown Title' && job.url) {
    jobs.push({ json: job });
  }
}

// If no jobs parsed, return empty with a flag
if (jobs.length === 0) {
  return [{ json: { noJobs: true, message: 'No jobs found in this batch' } }];
}

return jobs;

// ============================================
// KEYWORD FILTER - Customize these arrays!
// ============================================

const targetRoles = [
  // Add your target job titles/keywords here
  "automation engineer", "workflow automation",
  "data engineer", "integration engineer",
  "marketing automation", "sales automation",
  "ai engineer", "machine learning",
  "devops", "backend engineer"
];

const targetLocations = [
  "remote", "fully remote", "work from anywhere", "work from home",
  "wfh", "worldwide", "global", "100% remote", "distributed"
];

const excludeTerms = [
  "director", "vp ", "vice president", "head of", "chief", "c-level",
  "senior manager", "principal", "architect"
];




// ============================================
// FILTER LOGIC (no changes needed below)
// ============================================

const items = $input.all();
const matchedJobs = [];

for (const item of items) {
  const job = item.json;

  // Skip if it's the "no jobs" flag
  if (job.noJobs) continue;

  const titleLower = (job.title || '').toLowerCase();
  const locationLower = (job.location || '').toLowerCase();
  const descLower = (job.description || '').toLowerCase();
  const tagsLower = Array.isArray(job.tags) 
    ? job.tags.map(t => (typeof t === 'string' ? t : t.name || t.label || String(t)).toLowerCase()).join(' ')
    : '';

  const searchText = `${titleLower} ${descLower} ${tagsLower}`;

  // Check role match (title or tags)
  const roleMatch = targetRoles.some(role => 
    titleLower.includes(role) || tagsLower.includes(role)
  );

  // Check location match
  const locationMatch = targetLocations.some(loc => 
    locationLower.includes(loc)
  );

  // Check exclusions
  const isExcluded = excludeTerms.some(term => 
    titleLower.includes(term)
  );

  // Must match role AND location, and NOT be excluded
  if (roleMatch && locationMatch && !isExcluded) {
    matchedJobs.push({
      json: {
        ...job,
        matchedRole: targetRoles.find(r => titleLower.includes(r) || tagsLower.includes(r)),
        matchedLocation: targetLocations.find(l => locationLower.includes(l)),
        filterPassedAt: new Date().toISOString()
      }
    });
  }
}

if (matchedJobs.length === 0) {
  return [{ json: { noMatches: true, message: `No jobs matched filters. Checked ${items.length} jobs.`, checkedAt: new Date().toISOString() } }];
}

return matchedJobs;

// Deduplicate: compare current jobs against previously seen URLs

const currentJobs = $('✅ Has Valid Jobs?').all();
const seenJobsRaw = $('📋 Read Seen Jobs').all();

// Build a Set of previously seen URLs for O(1) lookup
const seenUrls = new Set();
for (const item of seenJobsRaw) {
  const url = (item.json.URL || item.json.url || item.json.uniqueId || '').toLowerCase().trim();
  if (url) seenUrls.add(url);
}

const newJobs = [];

for (const item of currentJobs) {
  const job = item.json;
  const jobUrl = (job.url || job.uniqueId || '').toLowerCase().trim();

  if (jobUrl && !seenUrls.has(jobUrl)) {
    newJobs.push({
      json: {
        ...job,
        isNew: true,
        deduplicatedAt: new Date().toISOString()
      }
    });
  }
}

if (newJobs.length === 0) {
  return [{ json: { noNewJobs: true, message: `All ${currentJobs.length} matched jobs were already seen.`, checkedAt: new Date().toISOString() } }];
}

return newJobs;

